{
  "title": "Customer Satisfaction Survey",
  "description": "Annual feedback survey.",
  "sections": [
    {
      "title": "Personal Info",
      "order": 1,
      "conditions": null,
      "fields": [
        {
          "label": "Full Name",
          "field_type": "text",
          "order": 1,
          "is_required": true,
          "maps_to": "respondent_full_name",
          "validation_rules": {"min_length": 2, "max_length": 100},
          "conditions": null
        },
        {
          "label": "Email Address",
          "field_type": "email",
          "order": 2,
          "is_required": true,
          "maps_to": "respondent_email",
          "validation_rules": {"max_length": 254},
          "conditions": null
        },
        {
          "label": "Phone Number",
          "field_type": "text",
          "order": 3,
          "is_required": false,
          "maps_to": "respondent_phone",
          "validation_rules": {"regex": "^\\+?[0-9\\s\\-]{7,15}$"},
          "conditions": null
        },
        {
          "label": "Do you own a car?",
          "field_type": "radio",
          "order": 4,
          "is_required": true,
          "options": ["Yes", "No"],
          "conditions": null
        }
      ]
    },
    {
      "title": "Vehicle Details",
      "order": 2,
      "conditions": {
        "conditions": [
          {
            "field_id": "<uuid-of-do-you-own-a-car-field>",
            "operator": "eq",
            "value": "Yes"
          }
        ]
      },
      "fields": [
        {
          "label": "Car Brand",
          "field_type": "dropdown",
          "order": 1,
          "is_required": true,
          "options": ["Toyota", "Honda", "Ford", "BMW", "Tesla", "Other"],
          "conditions": null
        },
        {
          "label": "Favourite Features",
          "field_type": "checkbox",
          "order": 2,
          "is_required": false,
          "options": ["Safety", "Fuel Economy", "Performance", "Design", "Tech"],
          "validation_rules": {"min_selections": 1, "max_selections": 3},
          "conditions": {
            "conditions": [
              {
                "field_id": "<uuid-of-car-brand-field>",
                "operator": "neq",
                "value": "Other"
              }
            ]
          }
        },
        {
          "label": "Year of Manufacture",
          "field_type": "number",
          "order": 3,
          "is_required": true,
          "validation_rules": {"min": 1990, "max": 2025},
          "conditions": null
        },
        {
          "label": "Purchase Date",
          "field_type": "date",
          "order": 4,
          "is_required": false,
          "validation_rules": {"min_date": "1990-01-01", "max_date": "2025-12-31"},
          "conditions": {
            "conditions": [
              {
                "field_id": "<uuid-of-year-of-manufacture-field>",
                "operator": "gte",
                "value": "2000"
              }
            ]
          }
        }
      ]
    },
    {
      "title": "General Feedback",
      "order": 3,
      "conditions": null,
      "fields": [
        {
          "label": "Additional Comments",
          "field_type": "textarea",
          "order": 1,
          "is_required": false,
          "validation_rules": {"max_length": 1000},
          "conditions": null
        },
        {
          "label": "Overall Satisfaction",
          "field_type": "rating",
          "order": 2,
          "is_required": true,
          "validation_rules": {"min": 1, "max": 5},
          "conditions": null
        }
      ]
    }
  ]
}
